        agents_map[agent_id]['identity'] = template_config['identity']
        if 'sandbox' in template_config:
            agents_map[agent_id]['sandbox'] = template_config['sandbox']
        if 'subagents' in template_config:
            agents_map[agent_id]['subagents'] = template_config['subagents']
        if 'workspace' in template_config:
            agents_map[agent_id]['workspace'] = template_config['workspace']
        # 删除不应该存在的subagents配置（中书省、门下省等）
        if agent_id in ['zhongshu', 'menxia', 'yushitai', 'bingbu', 'hubu', 'libu', 'gongbu', 'xingbu', 'libu2']:
